using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Numerics;

namespace Waher.Security.EllipticCurves.Test
{
	[TestClass]
	public class EcdsaTests
	{
		[TestMethod]
		[DataRow(
			"",
			"MA8PWqs7iYmS+V8u2ntn+zjTTWPqFbCqkPBvZxcYME5blWidZdTLX8kMb7SDhlCBXXubCFZK6SxQaOVjRvW5fRwJajAmamCNWoB8GZn/DN29EFYh2WmYGDWbJc87Qgc8GYdFRT7bTkkWWX2g3unL+5QF/rP5a8QO8RgxoduLxTo=",
			"jrUtRO8sr897v4K1OpxqlKg0q9WX1aFvxKPkqr23vnqwOeLIUY9cXLbZEah2st64s1YtY/etGORwVM34GQEt1zoXqqW0EHFZjOwIoVLmTmu8zYKJinashTalybP/iVFYPIlDHItrNYvIhfJIAyUwbHMhQt3j6tTJYeuEc9sRvDU=",
			true)]
		public void Test_01_Verify_BrainPoolP512(string Data, string PublicKey, string Signature,
			bool BigEndian)
		{
			BrainpoolP512 Curve = new();
			byte[] DataBin = Convert.FromBase64String(Data);
			byte[] PublicKeyBin = Convert.FromBase64String(PublicKey);
			byte[] SignatureBin = Convert.FromBase64String(Signature);

			Assert.IsTrue(ECDSA.Verify(DataBin, PublicKeyBin, BigEndian,
				Hashes.ComputeSHA512Hash, Curve, SignatureBin));
		}

		[TestMethod]
		[DataRow(
			"",
			"36386210842235564971068351558162971536197370878450437683580861819652105225341252943822817352316729172823081153085264",
			"28648247628603040742222434560531903617924449641018833319944870228617025531634912318017419588895606924950042487475185",
			"19612119776199782036515151206494248445862851162994849029689298301093944239768926298788661784755492666203708731105614",
			"13591636146683600703059669010259224858223254717342498381976125250376972739372529507294011485864612889593326580279973")]
		public void Test_02_Verify_NISTP384_SHA256(string Data, string PublicKeyX, 
			string PublicKeyY, string SignatureR, string SignatureS)
		{
			NistP384 Curve = new();
			byte[] DataBin = Convert.FromBase64String(Data);
			PointOnCurve PublicKey = new(
				BigInteger.Parse(PublicKeyX),
				BigInteger.Parse(PublicKeyY));
			BigInteger R = BigInteger.Parse(SignatureR);
			BigInteger S = BigInteger.Parse(SignatureS);

			Assert.IsTrue(Curve.IsPoint(PublicKey));

			Assert.IsTrue(ECDSA.Verify(DataBin, PublicKey, Hashes.ComputeSHA256Hash, 
				Curve, R, S));
		}

		[TestMethod]
		[DataRow(
			"",
			"4789982668500618565468763307146520609503793670709225708236973733180860110882223707790798413393498053803368736598128427917952060389292482027661946407052506567",
			"1855017156418300339612411069996209204330473557806287601086578153606304737593562740327051172950445202175234985363958681698328978326207093142383778742502399289",
			"5662646597548729484844005325266871087994456189935069135010281804618876761943247332800491517021647319472070541490831439402770567070292723942902508986954057442",
			"3066330105222122971589737545044611973150529235920438882579230315484798604021867549681068245077372704027309621173545248594420790902964289688015769196460861315")]
		public void Test_03_Verify_NISTP521_SHA512(string Data, string PublicKeyX, 
			string PublicKeyY, string SignatureR, string SignatureS)
		{
			NistP521 Curve = new();
			byte[] DataBin = Hashes.StringToBinary(Data);
			PointOnCurve PublicKey = new(
				BigInteger.Parse(PublicKeyX),
				BigInteger.Parse(PublicKeyY));
			BigInteger R = BigInteger.Parse(SignatureR);
			BigInteger S = BigInteger.Parse(SignatureS);

			Assert.IsTrue(Curve.IsPoint(PublicKey));

			Assert.IsTrue(ECDSA.Verify(DataBin, PublicKey, Hashes.ComputeSHA512Hash,
				Curve, R, S));
		}
	}
}
